import{_ as a,o,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"34. Shift Allowances","description":"","frontmatter":{"title":"34. Shift Allowances","eba":"Biomedical Engineers 2025-2028","topics":["hours","shift-work","rosters","allowances"]},"headers":[],"relativePath":"ebas/biomedical-engineers/allowances/34-shift-allowances.md","filePath":"ebas/biomedical-engineers/allowances/34-shift-allowances.md"}'),r={name:"ebas/biomedical-engineers/allowances/34-shift-allowances.md"};function i(s,e,l,c,h,f){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_34-shift-allowances" tabindex="-1">34. Shift Allowances <a class="header-anchor" href="#_34-shift-allowances" aria-label="Permalink to &quot;34. Shift Allowances&quot;">​</a></h1><p>The allowances payable pursuant to this clause shall be calculated to the nearest five cents, portions of a cent being disregarded.</p><p><strong>34.1</strong> Shift work allowance</p><p><strong>(a)</strong> In addition to any rates prescribed elsewhere in this Agreement, an Employee whose rostered hours of ordinary duty finish between 6:00pm and 8:00am or commence between 6:00pm and 6:30am shall be paid an amount equal to 2.5% of the rate applicable to first year of experience, Biomedical Engineer – Class 1 per rostered period of duty.</p><p><strong>(b)</strong> Provided that in the case of an Employee working on any rostered hours of ordinary duty finishing on the day after commencing duty or commencing after midnight and before 5:00am, they shall be paid for any such period of duty an amount equal to 4% of the rate applicable to first year of experience, Biomedical Engineer – Class 1 and provided further that in the case of an Employee permanently working on any such rostered hours of ordinary duty they shall be paid for any such period of duty an amount equal to 5% of the rate applicable to first year of experience, Biomedical Engineer – Class 1. Permanently working shall mean working any period in excess of four consecutive weeks.</p><p><strong>34.2</strong> Change of shift allowance Provided further that in the case of an Employee who changes from working on one shift to working on another shift the time of commencement of which differs by four hours or more from that of the first, they shall be paid an amount equal to 4% of the rate applicable to first year of experience, Biomedical Engineer – Class 1 on the occasion of each such change in addition to any amount payable under the preceding provisions of this clause.</p>',6)])])}const m=a(r,[["render",i]]);export{p as __pageData,m as default};
